async function createCollection(userId, data) {
  const [collection] = await db.insert(userCollections).values({ ...data, userId }).returning();
  return collection;
}

async function getCollectionsByUserId(userId) {
  return await db.query.userCollections.findMany({
    where: eq(userCollections.userId, userId),
    with: {
      items: true
    }
  });
}
async function getCollectionById(userId, collectionId) {
  return await db.query.userCollections.findFirst({
    where: and(eq(userCollections.id, collectionId), eq(userCollections.userId, userId)),
    with: {
      items: true
    }
  });
}

async function deleteCollection(userId, collectionId) {
  const [deleted] = await db.delete(userCollections).where(and(eq(userCollections.id, collectionId), eq(userCollections.userId, userId))).returning();
  return deleted;
}

async function addItemToCollection(collectionId, data) {
  const [existing] = await db.select().from(collectionItems).where(
    and(
      eq(collectionItems.collectionId, collectionId),
      eq(collectionItems.apiId, data.apiId)
    )
  );
  if (existing) return existing;
  const [item] = await db.insert(collectionItems).values({ ...data, collectionId }).returning();
  return item;
}

async function getItemsByCollectionId(collectionId) {
  return await db.select().from(collectionItems).where(eq(collectionItems.collectionId, collectionId));
}
async function getCollectionItemById(collectionId, itemId) {
  const [item] = await db.select().from(collectionItems).where(and(eq(collectionItems.id, itemId), eq(collectionItems.collectionId, collectionId)));
  return item;
}

async function removeItemFromCollection(collectionId, itemId) {
  const [deleted] = await db.delete(collectionItems).where(and(eq(collectionItems.id, itemId), eq(collectionItems.collectionId, collectionId))).returning();
  return deleted;
}

